from anthropic import Anthropic

client = Anthropic()

TOOL_SELECTION_PROMPT = """An agent was given these tools:
{tool_list}

The user asked: {user_input}
The agent called: {called_tool}

Questions:
1. Was {called_tool} the right tool for this request? (yes/no)
2. If no, which tool should have been called?
3. Tool selection score 0.0-1.0 (1.0 = perfect choice).

Return JSON: {{"correct": true/false, "should_have_called": null, "score": 0.0}}"""

def eval_tool_selection(
    user_input: str,
    available_tools: list[str],
    called_tool: str,
) -> dict:
    import json, re
    prompt = TOOL_SELECTION_PROMPT.format(
        tool_list=", ".join(available_tools),
        user_input=user_input,
        called_tool=called_tool,
    )
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=80,
        messages=[{"role": "user", "content": prompt}],
    )
    m = re.search(r'\{[^}]+\}', msg.content[0].text)
    if not m:
        return {"correct": False, "should_have_called": None, "score": 0.0}
    try:
        return json.loads(m.group())
    except json.JSONDecodeError:
        return {"correct": False, "should_have_called": None, "score": 0.0}

import jsonschema

def validate_args_against_schema(
    tool_name: str,
    args: dict,
    tool_schemas: dict[str, dict],
) -> dict:
    """
    Validate args against the tool's JSON schema.
    Returns a structured result with the specific validation error if any.
    """
    schema = tool_schemas.get(tool_name)
    if schema is None:
        return {"valid": False, "error": f"No schema found for tool '{tool_name}'"}
    try:
        jsonschema.validate(args, schema)
        return {"valid": True, "error": None}
    except jsonschema.ValidationError as e:
        return {"valid": False, "error": e.message}

