from dataclasses import dataclass
from statistics import mean

TOOL_SELECTION_WEIGHT = 0.25
ARG_QUALITY_WEIGHT    = 0.25
SEQUENCING_WEIGHT     = 0.25
ERROR_HANDLING_WEIGHT = 0.25

@dataclass
class ToolUseScorecard:
    selection_score: float
    arg_quality_score: float
    sequence_score: float
    error_handling_score: float

    def composite(self) -> float:
        return (
            TOOL_SELECTION_WEIGHT    * self.selection_score
            + ARG_QUALITY_WEIGHT     * self.arg_quality_score
            + SEQUENCING_WEIGHT      * self.sequence_score
            + ERROR_HANDLING_WEIGHT  * self.error_handling_score
        )

    def report(self) -> str:
        return (
            f"Composite tool use score: {self.composite():.2f}\n"
            f"  Selection:     {self.selection_score:.2f}\n"
            f"  Arg quality:   {self.arg_quality_score:.2f}\n"
            f"  Sequencing:    {self.sequence_score:.2f}\n"
            f"  Error handling:{self.error_handling_score:.2f}"
        )

def score_tool_use(
    case: dict,
    trajectory_steps: list[dict],
    final_output: str,
    tool_schemas: dict,
) -> ToolUseScorecard:
    tool_calls = [s for s in trajectory_steps if s.get("type") == "tool_use"]
    if not tool_calls:
        return ToolUseScorecard(1.0, 1.0, 1.0, 1.0)

    selection_scores = [
        eval_tool_selection(
            case["user_input"],
            list(tool_schemas.keys()),
            call["tool_name"],
        )["score"]
        for call in tool_calls
    ]
    arg_scores = [
        eval_arg_semantics(case["user_input"], call["tool_name"], call.get("args", {}))
        for call in tool_calls
    ]
    seq = eval_call_sequence(
        case["user_input"],
        [c["tool_name"] for c in tool_calls],
        case.get("expected_sequence"),
    )
    err = eval_error_handling(trajectory_steps, final_output, case["user_input"])

    return ToolUseScorecard(
        selection_score=mean(selection_scores),
        arg_quality_score=mean(arg_scores),
        sequence_score=seq["sequence_score"],
        error_handling_score=err["recovery_score"],
    )
